1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type Damage = { itemType: string; amount: number };
3	type Incident = { cause?: string; damages: Damage[] };
4	type QuoteStep = { op?: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer?: { yearsWithMHPCO?: number }; steps: Step[] };
8	
9	const PROCESSING_FEE = 5;
10	const COMPONENT_BASE_PER_ITEM = 25;
11	const COMPONENT_BLOCK_OF_THREE_BASE = 60;
12	
13	const CURSED_SURCHARGE_RATE = 0.5;
14	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
15	const FIRST_INSURANCE_MARKUP_RATE = 0.1;
16	const LOYALTY_DISCOUNT_RATE = 0.2;
17	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
18	const LOYALTY_YEARS_THRESHOLD = 2;
19	const HIGH_ENCHANTMENT_THRESHOLD = 5;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	const CAP_MULTIPLIER = 2;
23	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
24	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
25	
26	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	};
32	
33	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
34	  sword: 1000,
35	  amulet: 600,
36	  rune: 250,
37	};
38	
39	type PolicyState = { items: Item[]; remainingCap: number };
40	
41	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
42	
43	export function runScenario(input: unknown): unknown {
44	  const { customer, steps } = input as Scenario;
45	  const years = customer?.yearsWithMHPCO ?? 0;
46	  const policies: Record<number, PolicyState> = {};
47	  const results = steps.map((step, index) => {
48	    if (step.op === "claim") return computeClaim(step, policies);
49	    validateItemTypes(step.items);
50	    const isFollowUp = index >= 1;
51	    policies[index] = { items: step.items, remainingCap: CAP_MULTIPLIER * insuranceSumFor(step.items) };
52	    return { premium: computePremium(step.items, years, isFollowUp) };
53	  });
54	  return { results };
55	}
56	
57	function validateItemTypes(items: Item[]): void {
58	  for (const item of items) {
59	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
60	      throw new Error(`Unknown item type: ${item.type}`);
61	    }
62	  }
63	}
64	
65	function insuranceSumFor(items: Item[]): number {
66	  return items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
67	}
68	
69	function computeClaim(step: ClaimStep, policies: Record<number, PolicyState>): { payout: number; remainingCap: number } {
70	  const policy = policies[step.policy];
71	  const uncappedPayout = Math.floor(totalReimbursement(step.incident.damages, policy.items));
72	  const payout = Math.min(uncappedPayout, policy.remainingCap);
73	  policy.remainingCap -= payout;
74	  return { payout, remainingCap: policy.remainingCap };
75	}
76	
77	function totalReimbursement(damages: Damage[], items: Item[]): number {
78	  return damages.reduce((sum, damage) => sum + reimbursementFor(damage, items), 0);
79	}
80	
81	function reimbursementFor(damage: Damage, items: Item[]): number {
82	  const item = items.find((i) => i.type === damage.itemType);
83	  const rate = item !== undefined && isHighlyEnchantedForClaim(item) ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : 1;
84	  return Math.max(0, damage.amount * rate - CLAIM_DEDUCTIBLE);
85	}
86	
87	function isHighlyEnchantedForClaim(item: Item): boolean {
88	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
89	}
90	
91	function computePremium(items: Item[], years: number, isFollowUp: boolean): number {
92	  if (items.length === 0) return PROCESSING_FEE;
93	  if (items.every(isComponent)) return componentsPremium(items);
94	  return mainItemsPremium(items, years, isFollowUp);
95	}
96	
97	function mainItemsPremium(items: Item[], years: number, isFollowUp: boolean): number {
98	  const policyBase = items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
99	  const itemSubtotalSum = items.reduce((sum, item) => sum + itemSubtotal(item), 0);
100	  const policyMod = (cond: boolean, rate: number) => (cond ? policyBase * rate : 0);
101	  const loyaltyDiscount = policyMod(years >= LOYALTY_YEARS_THRESHOLD, LOYALTY_DISCOUNT_RATE);
102	  const followUpDiscount = policyMod(isFollowUp, FOLLOW_UP_DISCOUNT_RATE);
103	  return Math.ceil(itemSubtotalSum - loyaltyDiscount - followUpDiscount) + PROCESSING_FEE;
104	}
105	
106	function itemSubtotal(item: Item): number {
107	  const base = BASE_PREMIUM_BY_TYPE[item.type];
108	  const surchargeIf = (cond: boolean, rate: number) => (cond ? base * rate : 0);
109	  const cursedSurcharge = surchargeIf(item.cursed === true, CURSED_SURCHARGE_RATE);
110	  const highEnchSurcharge = surchargeIf(isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE_RATE);
111	  const firstInsuranceMarkup = base * FIRST_INSURANCE_MARKUP_RATE;
112	  return base + cursedSurcharge + highEnchSurcharge + firstInsuranceMarkup;
113	}
114	
115	function isHighlyEnchanted(item: Item): boolean {
116	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
117	}
118	
119	function componentsPremium(items: Item[]): number {
120	  const runes = items.filter((i) => i.type === "rune").length;
121	  const moonstones = items.filter((i) => i.type === "moonstone").length;
122	  return premiumFromBase(componentTypeBase(runes) + componentTypeBase(moonstones));
123	}
124	
125	function componentTypeBase(count: number): number {
126	  return count === 3 ? COMPONENT_BLOCK_OF_THREE_BASE : count * COMPONENT_BASE_PER_ITEM;
127	}
128	
129	function isComponent(item: Item): boolean {
130	  return item.type === "rune" || item.type === "moonstone";
131	}
132	
133	function premiumFromBase(base: number): number {
134	  return Math.ceil((base * 11) / 10) + PROCESSING_FEE;
135	}
